export function getCourseById(id) {
  return UCDAVIS_COURSES.find((course) => course.id === id);
}

// Case-insensitive substring match against name, code, and department - same "select from the
// real catalog, no free-text entry" contract Roslyn's own searchCourses() already established.
export function searchUCDavisCourses(query) {
  const q = query.trim().toLowerCase();
  if (!q) return [];
  return UCDAVIS_COURSES.filter(
    (course) =>
      course.name.toLowerCase().includes(q) ||
      course.code.toLowerCase().includes(q) ||
      course.department.toLowerCase().includes(q),
  );
}
